import re

def parse_config(input_str):
    try:
        line = input_str.strip()
        match = re.match(r"^SET\s+(\w+)\s*=\s*(.+)$", line, re.IGNORECASE)
        if not match: return None
        target, value_str = match.groups()
        tokens = tokenize_math(value_str.strip())
        if not tokens: return None
        return build_ast(tokens, 0)
    except Exception:
        return None

def tokenize_math(expr):
    tokens = re.findall(r'(\d+|\*|\+|[-a-zA-Z]*)', expr)
    return tokens[1:-1]

