def check_permission(user, action, resource):
    if user is None or action is None or resource is None:
        raise ValueError("All arguments must be provided.")

    role_hierarchy = {'admin', 'manager', 'editor', 'viewer'}

    if user.user_id == resource.owner_id:
        return True

    if not user.role in role_hierarchy:
