import math
from collections import Counter

def calculate_entropy(ip_list):
    try:
        if not ip_list:
            return 0.0

        counts = Counter(ip_list)
        total = len(ip_list)
        entropy = 0.0

        for _, count in counts.items():
            p = count / total
            if p > 0:
                entropy -= p * math.log2(p)

        return entropy
    except Exception:
        return 0.0
