class LSMTree:
    def __init__(self):
        self.mem_table = {}
        self.sstables = []
        self.flush_threshold = 100

    def put(self, key, value):
        if len(self.mem_table) < self.flush_threshold:
            self.mem_table[key] = value
        else:
            self.flush_mem_table()
            self.mem_table[key] = value

    def get(self, key):
        if key in self.mem_table:
            return self.mem_table[key]
        for sstable in self.sstables:
            if key in sstable:
                return sstable[key]
        return None

    def delete(self, key):
        if key in self.mem_table:
            del self.mem_table[key]
        for sstable in self.sstables:
            if key in sstable:
                del sstable[key]
                break

    def flush_mem_table(self):
        if self.mem_table:
            self.sstables.append(self.mem_table)
            self.mem_table = {}
